SET version_content = version_content || '{"root":{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"Details","type":"text","version":1}],"direction":null,"format":"","indent":0,"type":"heading","version":1,"tag":"h1"},{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":" ","type":"text","version":1}],"direction":null,"format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""},{"children":[{"children":[{"children":[{"children":[{"detail":0,"format":0,"mode":"normal","style":"","text":"If you''re looking for the perfect set up to prepare your decadent chocolate, the Sephra Aztec 27\" heavy-duty chocolate fountain has you covered. This fountain operates on a minimum of 6 lb. of chocolate and can hold up to 11 lb. of total chocolate. Not only can chocolate be used, but this fountain can even handle cheese fondue, BBQ sauce, caramel fondue, and ranch dressing , making it one of the most versatile fountains on the market.","type":"text","version":1},{"type":"linebreak","version":1},{"type":"linebreak","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":"For the perfect melt, this unit features a heated basin, so the product evenly softens and can beautifully cascade down the fountain''s tiers. The temperature is automatically set, so all you need to do is press the on / off control for operation. The fountain itself is designed with a brushed 304 food-grade stainless steel finish that''s durable and seamlessly fits into any event or gathering space. Plus, with a removable basin and food-grade, high-impact, plastic tiers, you can easily clean it without hassle.","type":"text","version":1},{"type":"linebreak","version":1},{"type":"linebreak","version":1},{"detail":0,"format":0,"mode":"normal","style":"","text":"This fountain includes a custom, double-wall, polymer travel case, ensuring it stays protected during transport. Try it with marshmallows, waffles, fresh fruit, pound cake, or fudge to liven up your next event! Between 75-150 guests can be served with this fountain. A 115V, 552W electrical connection is required for operation.","type":"text","version":1}],"direction":null,"format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":null,"format":"","indent":0,"type":"tablecell","version":1,"backgroundColor":null,"colSpan":1,"headerState":0,"rowSpan":1},{"children":[{"children":[{"type":"upload","version":3,"format":"","id":"69ce319902055850e2cdcfe3","fields":{},"relationTo":"media","value":4}],"direction":null,"format":"center","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":null,"format":"","indent":0,"type":"tablecell","version":1,"backgroundColor":null,"colSpan":1,"headerState":0,"rowSpan":1}],"direction":null,"format":"","indent":0,"type":"tablerow","version":1}],"direction":null,"format":"","indent":0,"type":"table","version":1},{"children":[{"children":[{"children":[{"children":[{"type":"upload","version":3,"format":"","id":"69ce319902055850e2cdcfe5","fields":{},"relationTo":"media","value":113}],"direction":null,"format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":null,"format":"","indent":0,"type":"tablecell","version":1,"backgroundColor":null,"colSpan":1,"headerState":0,"rowSpan":1},{"children":[{"children":[{"type":"upload","version":3,"format":"","id":"69ce319902055850e2cdcfe7","fields":{},"relationTo":"media","value":114}],"direction":null,"format":"","indent":0,"type":"paragraph","version":1,"textFormat":0,"textStyle":""}],"direction":null,"format":"","indent":0,"type":"tablecell","version":1,"backgroundColor":null,"colSpan":1,"headerState":0,"rowSpan":1}],"direction":null,"format":"","indent":0,"type":"tablerow","version":1}],"direction":null,"format":"","indent":0,"type":"table","version":1},{"children":[{"children":[{"children":[{"children":[{"detail":0,"format":1,"mode":"normal","style":"","text":"Mo